			const item = index.find((entry) => entry.name === component);
			if (!item) {
				logger.error(`Component ${highlighter.info(component)} not found in the shadcn-vue registry.`);
				process.exit(1);
			}
			const metaLinks = (item.meta?.links)?.[base];
			let links;
